def solve(nums: Array[Long], k: Long): Long = {
  return 0L when nums.length == 1

  val sorted_nums = nums.sorted
  val n = nums.length
  var min_removals = n

  for (i <- 0 until n) {
    var left = i
    var right = n - 1
    while (left < right) {
      val mid = (left + right) / 2
      if (sorted_nums(mid) >= sorted_nums(i) * k) {
        right = mid
      } else {
        left = mid + 1
      }
    }

    val current_removals = i + (n - 1 - right)
    min_removals = math.min(min_removals, current_removals)
  }

  min_removals
}
